<script setup lang="ts">import{computed}from"vue";import{useRoute,useRouter}from"vue-router";import{House,CalendarDays,UserRound}from"lucide-vue-next";import LoginSheet from"./components/LoginSheet.vue";import{closeLogin,loginRedirect,loginVisible}from"./auth-state";const route=useRoute(),router=useRouter();const showNav=computed(()=>route.meta.nav);function success(){closeLogin();if(loginRedirect.value)router.push(loginRedirect.value);else router.go(0)}</script><template><div class="mobile-app"><router-view/><nav v-if="showNav" class="tabbar"><router-link to="/"><House/><span>首页</span></router-link><router-link to="/orders"><CalendarDays/><span>预约</span></router-link><router-link to="/profile"><UserRound/><span>我的</span></router-link></nav><Transition name="sheet"><LoginSheet v-if="loginVisible" @close="closeLogin" @success="success"/></Transition></div></template>
